+func looksLikeCustomLabelID(raw string) bool {
+	trimmed := strings.TrimSpace(raw)
+	if !strings.HasPrefix(strings.ToLower(trimmed), "label_") {
+		return false
+	}
+
+	_, err := strconv.ParseInt(trimmed[len("Label_"):], 10, 64)
+	return err == nil
+}
